mapper.select:
/* wms-system-centerconfigsetup-sql-oracle.xml - selectCtcsList */
SELECT '0' AS CHK , CTCS.CTKEY , CT.CTNM , CTCS.CTCSKEY , CTCS.CTCSNM , CTCS.DEFAULTVALUE , CTCS.VALUE1 , CTCS.VALUE2 , CTCS.INSERTDATE , CTCS.INSERTURKEY , CTCS.UPDATEDATE , CTCS.UPDATEURKEY
ORDER BY CTCS.UPDATEURKEY DESC

/* wms-system-centerconfigsetup-sql-oracle.xml - selectCtcsDupCheckCount */
SELECT COUNT(1)
  FROM TWORK_SET_CTCS
 WHERE CTKEY = #{ctkey}
   AND CTCSKEY = #{ctcskey}

mapper.insert:
	/* wms-system-centerconfigsetup-sql-oracle.xml - insertCtcs */
	INSERT INTO TWORK_SET_CTCS (
		   CTKEY
	     , CTCSKEY
		 , CTCSNM
		 , DEFAULTVALUE
		 , VALUE1
		 , VALUE2
		 , INSERTDATE
		 , INSERTURKEY
		 , UPDATEDATE
		 , UPDATEURKEY
 		 )
    VALUES (
		   #{ctkey}
		 , #{ctcskey}
		 , #{ctcsnm}
		 , #{defaultvalue}
		 , #{value1}
		 , #{value2}
		 , #{sysdate}
		 , #{surkey}
		 , #{sysdate}
		 , #{surkey}
		 )

mapper.update:
/* wms-system-centerconfigsetup-sql-oracle.xml - updateCtcs */
UPDATE TWORK_SET_CTCS
   SET CTCSNM = #{ctcsnm}
	 , DEFAULTVALUE = #{defaultvalue}
	 , VALUE1 = #{value1}
	 , VALUE2 = #{value2}
     , UPDATEDATE = #{sysdate}
     , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND CTCSKEY = #{ctcskey}

mapper.delete:
/* wms-system-centerconfigsetup-sql-oracle.xml - deleteCtcs */
DELETE 
  FROM TWORK_SET_CTCS
 WHERE CTKEY = #{ctkey}
   AND CTCSKEY = #{ctcskey}
